import{_ as t,o as a,c as s,ae as o}from"./chunks/framework.BEtfQoF7.js";const k=JSON.parse('{"title":"모델 설정","description":"opusplan과 같은 모델 별칭을 포함한 Claude Code 모델 설정에 대해 알아보세요.","frontmatter":{"title":"모델 설정","description":"opusplan과 같은 모델 별칭을 포함한 Claude Code 모델 설정에 대해 알아보세요."},"headers":[],"relativePath":"model-config.md","filePath":"model-config.md","lastUpdated":1776205703000}'),d={name:"model-config.md"};function i(l,e,n,c,p,r){return a(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="모델-설정" tabindex="-1">모델 설정 <a class="header-anchor" href="#모델-설정" aria-label="Permalink to &quot;모델 설정&quot;">​</a></h1><h2 id="사용-가능한-모델" tabindex="-1">사용 가능한 모델 <a class="header-anchor" href="#사용-가능한-모델" aria-label="Permalink to &quot;사용 가능한 모델&quot;">​</a></h2><p>Claude Code의 <code>model</code> 설정에서 다음 중 하나를 구성할 수 있습니다:</p><ul><li><strong>모델 별칭</strong></li><li><strong>모델 이름</strong><ul><li>Anthropic API: 전체 <strong><a href="https://platform.claude.com/docs/en/about-claude/models/overview" target="_blank" rel="noreferrer">모델 이름</a></strong></li><li>Bedrock: 추론 프로파일 ARN</li><li>Foundry: 배포 이름</li><li>Vertex: 버전 이름</li></ul></li></ul><h3 id="모델-별칭" tabindex="-1">모델 별칭 <a class="header-anchor" href="#모델-별칭" aria-label="Permalink to &quot;모델 별칭&quot;">​</a></h3><p>모델 별칭은 정확한 버전 번호를 기억하지 않고도 모델 설정을 편리하게 선택할 수 있는 방법을 제공합니다:</p><table tabindex="0"><thead><tr><th>모델 별칭</th><th>동작</th></tr></thead><tbody><tr><td><strong><code>default</code></strong></td><td>모델 재정의를 지우고 계정 유형에 맞는 권장 모델로 되돌리는 특수 값. 자체적으로 모델 별칭은 아님</td></tr><tr><td><strong><code>best</code></strong></td><td>현재 <code>opus</code>에 해당하는 가장 성능 좋은 모델 사용</td></tr><tr><td><strong><code>sonnet</code></strong></td><td>일상적인 코딩 작업을 위한 최신 Sonnet 모델(현재 Sonnet 4.6) 사용</td></tr><tr><td><strong><code>opus</code></strong></td><td>복잡한 추론 작업을 위한 최신 Opus 모델(현재 Opus 4.6) 사용</td></tr><tr><td><strong><code>haiku</code></strong></td><td>간단한 작업을 위한 빠르고 효율적인 Haiku 모델 사용</td></tr><tr><td><strong><code>sonnet[1m]</code></strong></td><td>긴 세션을 위한 <a href="https://platform.claude.com/docs/en/build-with-claude/context-windows#1m-token-context-window" target="_blank" rel="noreferrer">100만 토큰 컨텍스트 창</a>이 있는 Sonnet 사용</td></tr><tr><td><strong><code>opus[1m]</code></strong></td><td>긴 세션을 위한 <a href="https://platform.claude.com/docs/en/build-with-claude/context-windows#1m-token-context-window" target="_blank" rel="noreferrer">100만 토큰 컨텍스트 창</a>이 있는 Opus 사용</td></tr><tr><td><strong><code>opusplan</code></strong></td><td>플랜 모드에서는 <code>opus</code>를 사용하고 실행 시에는 <code>sonnet</code>으로 전환하는 특수 모드</td></tr></tbody></table><p>별칭은 항상 최신 버전을 가리킵니다. 특정 버전에 고정하려면 전체 모델 이름(예: <code>claude-opus-4-6</code>)을 사용하거나 <code>ANTHROPIC_DEFAULT_OPUS_MODEL</code>과 같은 해당 환경 변수를 설정하세요.</p><h3 id="모델-설정하기" tabindex="-1">모델 설정하기 <a class="header-anchor" href="#모델-설정하기" aria-label="Permalink to &quot;모델 설정하기&quot;">​</a></h3><p>우선순위 순서대로 여러 가지 방법으로 모델을 구성할 수 있습니다:</p><ol><li><strong>세션 중</strong> - <code>/model &lt;별칭|이름&gt;</code>을 사용하여 세션 중 모델 전환</li><li><strong>시작 시</strong> - <code>claude --model &lt;별칭|이름&gt;</code>으로 실행</li><li><strong>환경 변수</strong> - <code>ANTHROPIC_MODEL=&lt;별칭|이름&gt;</code> 설정</li><li><strong>설정</strong> - <code>model</code> 필드를 사용하여 설정 파일에 영구적으로 구성</li></ol><p>사용 예시:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Opus로 시작</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> opus</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 세션 중 Sonnet으로 전환</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sonnet</span></span></code></pre></div><p>설정 파일 예시:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;permissions&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">        ...</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;model&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;opus&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="모델-선택-제한" tabindex="-1">모델 선택 제한 <a class="header-anchor" href="#모델-선택-제한" aria-label="Permalink to &quot;모델 선택 제한&quot;">​</a></h2><p>엔터프라이즈 관리자는 <a href="/claude-code-docs-ko/settings.html#settings-files">관리 또는 정책 설정</a>의 <code>availableModels</code>를 사용하여 사용자가 선택할 수 있는 모델을 제한할 수 있습니다.</p><p><code>availableModels</code>가 설정되면 사용자는 <code>/model</code>, <code>--model</code> 플래그, Config 도구 또는 <code>ANTHROPIC_MODEL</code> 환경 변수를 통해 목록에 없는 모델로 전환할 수 없습니다.</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;availableModels&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;sonnet&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;haiku&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="기본-모델-동작" tabindex="-1">기본 모델 동작 <a class="header-anchor" href="#기본-모델-동작" aria-label="Permalink to &quot;기본 모델 동작&quot;">​</a></h3><p>모델 선택기의 Default 옵션은 <code>availableModels</code>의 영향을 받지 않습니다. 항상 사용 가능하며 <a href="#default-model-setting">사용자의 구독 등급에 따른</a> 시스템의 런타임 기본값을 나타냅니다.</p><p><code>availableModels: []</code>로 설정하더라도 사용자는 자신의 등급에 맞는 Default 모델로 Claude Code를 사용할 수 있습니다.</p><h3 id="사용자가-실행하는-모델-제어" tabindex="-1">사용자가 실행하는 모델 제어 <a class="header-anchor" href="#사용자가-실행하는-모델-제어" aria-label="Permalink to &quot;사용자가 실행하는 모델 제어&quot;">​</a></h3><p><code>model</code> 설정은 초기 선택이지, 강제 적용은 아닙니다. 세션 시작 시 어떤 모델이 활성화될지를 설정하지만, 사용자는 여전히 <code>/model</code>을 열고 Default를 선택할 수 있으며, 이는 <code>model</code>에 설정된 값에 관계없이 해당 등급의 시스템 기본값으로 해석됩니다.</p><p>모델 경험을 완전히 제어하려면 세 가지 설정을 함께 사용하세요:</p><ul><li><strong><code>availableModels</code></strong>: 사용자가 전환할 수 있는 명명된 모델 제한</li><li><strong><code>model</code></strong>: 세션 시작 시 초기 모델 선택 설정</li><li><strong><code>ANTHROPIC_DEFAULT_SONNET_MODEL</code></strong> / <strong><code>ANTHROPIC_DEFAULT_OPUS_MODEL</code></strong> / <strong><code>ANTHROPIC_DEFAULT_HAIKU_MODEL</code></strong>: Default 옵션과 <code>sonnet</code>, <code>opus</code>, <code>haiku</code> 별칭이 해석되는 모델 제어</li></ul><p>이 예시는 사용자를 Sonnet 4.5로 시작하고, 선택기를 Sonnet과 Haiku로 제한하며, Default가 최신 릴리스가 아닌 Sonnet 4.5로 해석되도록 고정합니다:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;model&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;claude-sonnet-4-5&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;availableModels&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;claude-sonnet-4-5&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;haiku&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;env&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;ANTHROPIC_DEFAULT_SONNET_MODEL&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;claude-sonnet-4-5&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><code>env</code> 블록 없이는 선택기에서 Default를 선택한 사용자가 최신 Sonnet 릴리스를 받게 되어 <code>model</code> 및 <code>availableModels</code>의 버전 고정을 우회하게 됩니다.</p><h3 id="병합-동작" tabindex="-1">병합 동작 <a class="header-anchor" href="#병합-동작" aria-label="Permalink to &quot;병합 동작&quot;">​</a></h3><p><code>availableModels</code>가 여러 수준(예: 사용자 설정과 프로젝트 설정)에서 설정되면 배열이 병합되고 중복이 제거됩니다. 엄격한 허용 목록을 적용하려면 가장 높은 우선순위를 갖는 관리 또는 정책 설정에서 <code>availableModels</code>를 설정하세요.</p><h3 id="mantle-모델-id" tabindex="-1">Mantle 모델 ID <a class="header-anchor" href="#mantle-모델-id" aria-label="Permalink to &quot;Mantle 모델 ID&quot;">​</a></h3><p><a href="/claude-code-docs-ko/amazon-bedrock.html#use-the-mantle-endpoint">Bedrock Mantle 엔드포인트</a>가 활성화되면 <code>anthropic.</code>으로 시작하는 <code>availableModels</code>의 항목이 <code>/model</code> 선택기에 사용자 정의 옵션으로 추가되고 Mantle 엔드포인트로 라우팅됩니다. 이는 <a href="#pin-models-for-third-party-deployments">서드파티 배포를 위한 모델 고정</a>에서 설명된 별칭 전용 매칭의 예외입니다. 설정은 여전히 나열된 항목으로만 선택기를 제한하므로 Mantle ID와 함께 표준 별칭도 포함하세요.</p><h2 id="특수-모델-동작" tabindex="-1">특수 모델 동작 <a class="header-anchor" href="#특수-모델-동작" aria-label="Permalink to &quot;특수 모델 동작&quot;">​</a></h2><h3 id="default-모델-설정" tabindex="-1"><code>default</code> 모델 설정 <a class="header-anchor" href="#default-모델-설정" aria-label="Permalink to &quot;\`default\` 모델 설정&quot;">​</a></h3><p><code>default</code>의 동작은 계정 유형에 따라 다릅니다:</p><ul><li><strong>Max 및 Team Premium</strong>: 기본값은 Opus 4.6</li><li><strong>Pro 및 Team Standard</strong>: 기본값은 Sonnet 4.6</li><li><strong>Enterprise</strong>: Opus 4.6을 사용할 수 있지만 기본값은 아님</li></ul><p>Claude Code는 Opus 사용량 한도에 도달하면 자동으로 Sonnet으로 폴백할 수 있습니다.</p><h3 id="opusplan-모델-설정" tabindex="-1"><code>opusplan</code> 모델 설정 <a class="header-anchor" href="#opusplan-모델-설정" aria-label="Permalink to &quot;\`opusplan\` 모델 설정&quot;">​</a></h3><p><code>opusplan</code> 모델 별칭은 자동화된 하이브리드 방식을 제공합니다:</p><ul><li><strong>플랜 모드에서</strong> - 복잡한 추론 및 아키텍처 결정에 <code>opus</code> 사용</li><li><strong>실행 모드에서</strong> - 코드 생성 및 구현을 위해 자동으로 <code>sonnet</code>으로 전환</li></ul><p>이를 통해 두 가지 장점을 모두 얻을 수 있습니다: 계획에는 Opus의 뛰어난 추론 능력을, 실행에는 Sonnet의 효율성을 활용합니다.</p><h3 id="노력-수준-조정" tabindex="-1">노력 수준 조정 <a class="header-anchor" href="#노력-수준-조정" aria-label="Permalink to &quot;노력 수준 조정&quot;">​</a></h3><p><a href="https://platform.claude.com/docs/en/build-with-claude/effort" target="_blank" rel="noreferrer">노력 수준</a>은 작업 복잡도에 따라 사고를 동적으로 할당하는 적응형 추론을 제어합니다. 낮은 노력은 간단한 작업에서 더 빠르고 저렴하며, 높은 노력은 복잡한 문제에 대해 더 깊은 추론을 제공합니다.</p><p>세 가지 수준이 세션 간에 유지됩니다: <strong>low</strong>, <strong>medium</strong>, <strong>high</strong>. 네 번째 수준인 <strong>max</strong>는 토큰 지출에 제약 없이 가장 깊은 추론을 제공하므로 응답이 <code>high</code>보다 느리고 비용이 더 많이 듭니다. <code>max</code>는 Opus 4.6에서만 사용 가능하며 <code>CLAUDE_CODE_EFFORT_LEVEL</code> 환경 변수를 통한 경우를 제외하고는 세션 간에 유지되지 않습니다.</p><p>기본 노력 수준은 플랜에 따라 다릅니다. Pro 및 Max 구독자는 기본적으로 medium 노력을 사용합니다. API 키, Team, Enterprise, 서드파티 제공자(Bedrock, Vertex AI, Foundry) 사용자를 포함한 다른 모든 사용자는 기본적으로 high 노력을 사용합니다.</p><p>플랜의 기본값은 대부분의 코딩 작업에 적합합니다. 어려운 디버깅 문제나 복잡한 아키텍처 결정과 같이 더 깊은 추론이 필요한 작업에는 노력 수준을 높이세요. 높은 수준은 일상적인 작업에서 모델이 과도하게 생각하게 할 수 있습니다.</p><p>세션 설정을 변경하지 않고 일회성 깊은 추론을 위해서는 프롬프트에 &quot;ultrathink&quot;를 포함하면 해당 턴에만 high 노력이 트리거됩니다. 세션이 이미 high 또는 max 상태라면 효과가 없습니다.</p><p><strong>노력 수준 설정:</strong></p><ul><li><strong><code>/effort</code></strong>: <code>/effort low</code>, <code>/effort medium</code>, <code>/effort high</code>, 또는 <code>/effort max</code>를 실행하여 수준을 변경하거나, <code>/effort auto</code>로 모델 기본값으로 재설정</li><li><strong><code>/model</code>에서</strong>: 모델 선택 시 왼쪽/오른쪽 화살표 키를 사용하여 노력 슬라이더 조정</li><li><strong><code>--effort</code> 플래그</strong>: Claude Code 실행 시 <code>low</code>, <code>medium</code>, <code>high</code>, 또는 <code>max</code>를 전달하여 단일 세션의 수준 설정</li><li><strong>환경 변수</strong>: <code>CLAUDE_CODE_EFFORT_LEVEL</code>을 <code>low</code>, <code>medium</code>, <code>high</code>, <code>max</code>, 또는 <code>auto</code>로 설정</li><li><strong>설정</strong>: 설정 파일에서 <code>effortLevel</code>을 <code>&quot;low&quot;</code>, <code>&quot;medium&quot;</code>, 또는 <code>&quot;high&quot;</code>로 설정</li><li><strong>스킬 및 서브에이전트 프론트매터</strong>: <a href="/claude-code-docs-ko/skills.html#frontmatter-reference">스킬</a> 또는 <a href="/claude-code-docs-ko/sub-agents.html#supported-frontmatter-fields">서브에이전트</a> 마크다운 파일에서 <code>effort</code>를 설정하여 해당 스킬이나 서브에이전트가 실행될 때 노력 수준 재정의</li></ul><p>환경 변수는 다른 모든 방법보다 우선하며, 그 다음으로 구성된 수준, 그 다음으로 모델 기본값이 적용됩니다. 프론트매터 노력은 해당 스킬이나 서브에이전트가 활성화될 때 적용되며, 세션 수준을 재정의하지만 환경 변수는 재정의하지 않습니다.</p><p>노력 수준은 Opus 4.6 및 Sonnet 4.6에서 지원됩니다. 지원되는 모델이 선택된 경우 <code>/model</code>에서 노력 슬라이더가 표시됩니다. 현재 노력 수준은 로고와 스피너 옆에도 표시됩니다(예: &quot;with low effort&quot;). 이를 통해 <code>/model</code>을 열지 않고도 어떤 설정이 활성화되어 있는지 확인할 수 있습니다.</p><p>Opus 4.6 및 Sonnet 4.6에서 적응형 추론을 비활성화하고 이전의 고정된 사고 예산으로 되돌리려면 <code>CLAUDE_CODE_DISABLE_ADAPTIVE_THINKING=1</code>을 설정하세요. 비활성화된 경우 이러한 모델은 <code>MAX_THINKING_TOKENS</code>로 제어되는 고정 예산을 사용합니다. <a href="/claude-code-docs-ko/env-vars.html">환경 변수</a>를 참조하세요.</p><h3 id="확장-컨텍스트" tabindex="-1">확장 컨텍스트 <a class="header-anchor" href="#확장-컨텍스트" aria-label="Permalink to &quot;확장 컨텍스트&quot;">​</a></h3><p>Opus 4.6 및 Sonnet 4.6은 대규모 코드베이스를 사용하는 긴 세션을 위한 <a href="https://platform.claude.com/docs/en/build-with-claude/context-windows#1m-token-context-window" target="_blank" rel="noreferrer">100만 토큰 컨텍스트 창</a>을 지원합니다.</p><p>가용성은 모델과 플랜에 따라 다릅니다. Max, Team, Enterprise 플랜에서는 추가 구성 없이 Opus가 자동으로 1M 컨텍스트로 업그레이드됩니다. 이는 Team Standard 및 Team Premium 시트 모두에 적용됩니다.</p><table tabindex="0"><thead><tr><th>플랜</th><th>1M 컨텍스트의 Opus 4.6</th><th>1M 컨텍스트의 Sonnet 4.6</th></tr></thead><tbody><tr><td>Max, Team, Enterprise</td><td>구독에 포함</td><td><a href="https://support.claude.com/en/articles/12429409-extra-usage-for-paid-claude-plans" target="_blank" rel="noreferrer">추가 사용량</a> 필요</td></tr><tr><td>Pro</td><td><a href="https://support.claude.com/en/articles/12429409-extra-usage-for-paid-claude-plans" target="_blank" rel="noreferrer">추가 사용량</a> 필요</td><td><a href="https://support.claude.com/en/articles/12429409-extra-usage-for-paid-claude-plans" target="_blank" rel="noreferrer">추가 사용량</a> 필요</td></tr><tr><td>API 및 종량제</td><td>전체 액세스</td><td>전체 액세스</td></tr></tbody></table><p>1M 컨텍스트를 완전히 비활성화하려면 <code>CLAUDE_CODE_DISABLE_1M_CONTEXT=1</code>을 설정하세요. 이렇게 하면 모델 선택기에서 1M 모델 변형이 제거됩니다. <a href="/claude-code-docs-ko/env-vars.html">환경 변수</a>를 참조하세요.</p><p>1M 컨텍스트 창은 200K를 초과하는 토큰에 대해 프리미엄 없이 표준 모델 가격을 사용합니다. 구독에 확장 컨텍스트가 포함된 플랜의 경우 사용량은 구독으로 처리됩니다. 추가 사용량을 통해 확장 컨텍스트에 액세스하는 플랜의 경우 토큰은 추가 사용량으로 청구됩니다.</p><p>계정이 1M 컨텍스트를 지원하는 경우 Claude Code의 최신 버전에서 모델 선택기(<code>/model</code>)에 옵션이 나타납니다. 보이지 않는다면 세션을 다시 시작해 보세요.</p><p>모델 별칭 또는 전체 모델 이름과 함께 <code>[1m]</code> 접미사를 사용할 수도 있습니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># opus[1m] 또는 sonnet[1m] 별칭 사용</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> opus[1m]</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sonnet[1m]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 또는 전체 모델 이름에 [1m] 추가</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude-opus-4-6[1m]</span></span></code></pre></div><h2 id="현재-모델-확인하기" tabindex="-1">현재 모델 확인하기 <a class="header-anchor" href="#현재-모델-확인하기" aria-label="Permalink to &quot;현재 모델 확인하기&quot;">​</a></h2><p>현재 사용 중인 모델을 여러 가지 방법으로 확인할 수 있습니다:</p><ol><li><a href="/claude-code-docs-ko/statusline.html">상태 표시줄</a>에서 (구성된 경우)</li><li><code>/status</code>에서, 계정 정보도 표시됩니다.</li></ol><h2 id="사용자-정의-모델-옵션-추가" tabindex="-1">사용자 정의 모델 옵션 추가 <a class="header-anchor" href="#사용자-정의-모델-옵션-추가" aria-label="Permalink to &quot;사용자 정의 모델 옵션 추가&quot;">​</a></h2><p><code>ANTHROPIC_CUSTOM_MODEL_OPTION</code>을 사용하여 기본 제공 별칭을 교체하지 않고 <code>/model</code> 선택기에 단일 사용자 정의 항목을 추가하세요. LLM 게이트웨이 배포나 Claude Code가 기본적으로 나열하지 않는 모델 ID를 테스트할 때 유용합니다.</p><p>이 예시는 게이트웨이를 통해 라우팅되는 Opus 배포를 선택 가능하도록 세 가지 변수를 모두 설정합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ANTHROPIC_CUSTOM_MODEL_OPTION</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;my-gateway/claude-opus-4-6&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ANTHROPIC_CUSTOM_MODEL_OPTION_NAME</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Opus via Gateway&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ANTHROPIC_CUSTOM_MODEL_OPTION_DESCRIPTION</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Custom deployment routed through the internal LLM gateway&quot;</span></span></code></pre></div><p>사용자 정의 항목은 <code>/model</code> 선택기 하단에 나타납니다. <code>ANTHROPIC_CUSTOM_MODEL_OPTION_NAME</code> 및 <code>ANTHROPIC_CUSTOM_MODEL_OPTION_DESCRIPTION</code>은 선택 사항입니다. 생략하면 모델 ID가 이름으로 사용되고 설명은 기본적으로 <code>Custom model (&lt;model-id&gt;)</code>가 됩니다.</p><p>Claude Code는 <code>ANTHROPIC_CUSTOM_MODEL_OPTION</code>에 설정된 모델 ID에 대한 검증을 건너뛰므로 API 엔드포인트가 허용하는 모든 문자열을 사용할 수 있습니다.</p><h2 id="환경-변수" tabindex="-1">환경 변수 <a class="header-anchor" href="#환경-변수" aria-label="Permalink to &quot;환경 변수&quot;">​</a></h2><p>다음 환경 변수를 사용할 수 있으며, 이는 별칭이 매핑되는 모델 이름을 제어하기 위해 전체 <strong>모델 이름</strong>(또는 API 제공자에 해당하는 값)이어야 합니다.</p><table tabindex="0"><thead><tr><th>환경 변수</th><th>설명</th></tr></thead><tbody><tr><td><code>ANTHROPIC_DEFAULT_OPUS_MODEL</code></td><td><code>opus</code>에 사용할 모델, 또는 Plan Mode가 활성화된 경우 <code>opusplan</code>에 사용할 모델</td></tr><tr><td><code>ANTHROPIC_DEFAULT_SONNET_MODEL</code></td><td><code>sonnet</code>에 사용할 모델, 또는 Plan Mode가 활성화되지 않은 경우 <code>opusplan</code>에 사용할 모델</td></tr><tr><td><code>ANTHROPIC_DEFAULT_HAIKU_MODEL</code></td><td><code>haiku</code>에 사용할 모델, 또는 <a href="/claude-code-docs-ko/costs.html#background-token-usage">백그라운드 기능</a></td></tr><tr><td><code>CLAUDE_CODE_SUBAGENT_MODEL</code></td><td><a href="/claude-code-docs-ko/sub-agents.html">서브에이전트</a>에 사용할 모델</td></tr></tbody></table><p>참고: <code>ANTHROPIC_SMALL_FAST_MODEL</code>은 <code>ANTHROPIC_DEFAULT_HAIKU_MODEL</code>을 위해 더 이상 사용되지 않습니다.</p><h3 id="서드파티-배포를-위한-모델-고정" tabindex="-1">서드파티 배포를 위한 모델 고정 <a class="header-anchor" href="#서드파티-배포를-위한-모델-고정" aria-label="Permalink to &quot;서드파티 배포를 위한 모델 고정&quot;">​</a></h3><p><a href="/claude-code-docs-ko/amazon-bedrock.html">Bedrock</a>, <a href="/claude-code-docs-ko/google-vertex-ai.html">Vertex AI</a>, 또는 <a href="/claude-code-docs-ko/microsoft-foundry.html">Foundry</a>를 통해 Claude Code를 배포할 때는 사용자에게 배포하기 전에 모델 버전을 고정하세요.</p><p>고정하지 않으면 Claude Code는 최신 버전으로 해석되는 모델 별칭(<code>sonnet</code>, <code>opus</code>, <code>haiku</code>)을 사용합니다. Anthropic이 사용자 계정에서 아직 활성화되지 않은 새 모델을 릴리스하면 Bedrock 및 Vertex AI 사용자는 알림을 보고 해당 세션에서 이전 버전으로 폴백하며, Foundry는 동등한 시작 검사가 없어 Foundry 사용자는 오류를 보게 됩니다.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>초기 설정의 일부로 세 가지 모델 환경 변수 모두를 특정 버전 ID로 설정하세요. 고정을 통해 사용자가 새 모델로 이동하는 시기를 제어할 수 있습니다.</p></div><p>제공자별 버전별 모델 ID와 함께 다음 환경 변수를 사용하세요:</p><table tabindex="0"><thead><tr><th style="text-align:left;">제공자</th><th style="text-align:left;">예시</th></tr></thead><tbody><tr><td style="text-align:left;">Bedrock</td><td style="text-align:left;"><code>export ANTHROPIC_DEFAULT_OPUS_MODEL=&#39;us.anthropic.claude-opus-4-6-v1&#39;</code></td></tr><tr><td style="text-align:left;">Vertex AI</td><td style="text-align:left;"><code>export ANTHROPIC_DEFAULT_OPUS_MODEL=&#39;claude-opus-4-6&#39;</code></td></tr><tr><td style="text-align:left;">Foundry</td><td style="text-align:left;"><code>export ANTHROPIC_DEFAULT_OPUS_MODEL=&#39;claude-opus-4-6&#39;</code></td></tr></tbody></table><p><code>ANTHROPIC_DEFAULT_SONNET_MODEL</code> 및 <code>ANTHROPIC_DEFAULT_HAIKU_MODEL</code>에도 동일한 패턴을 적용하세요. 모든 제공자의 현재 및 이전 모델 ID는 <a href="https://platform.claude.com/docs/en/about-claude/models/overview" target="_blank" rel="noreferrer">모델 개요</a>를 참조하세요. 사용자를 새 모델 버전으로 업그레이드하려면 이 환경 변수를 업데이트하고 재배포하세요.</p><p>고정된 모델에 <a href="#extended-context">확장 컨텍스트</a>를 활성화하려면 <code>ANTHROPIC_DEFAULT_OPUS_MODEL</code> 또는 <code>ANTHROPIC_DEFAULT_SONNET_MODEL</code>의 모델 ID에 <code>[1m]</code>을 추가하세요:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ANTHROPIC_DEFAULT_OPUS_MODEL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;claude-opus-4-6[1m]&#39;</span></span></code></pre></div><p><code>[1m]</code> 접미사는 <code>opusplan</code>을 포함한 해당 별칭의 모든 사용에 1M 컨텍스트 창을 적용합니다. Claude Code는 제공자에게 모델 ID를 보내기 전에 접미사를 제거합니다. Opus 4.6 또는 Sonnet 4.6과 같이 기반 모델이 1M 컨텍스트를 지원하는 경우에만 <code>[1m]</code>을 추가하세요.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p><code>settings.availableModels</code> 허용 목록은 서드파티 제공자를 사용할 때도 여전히 적용됩니다. 필터링은 제공자별 모델 ID가 아닌 모델 별칭(<code>opus</code>, <code>sonnet</code>, <code>haiku</code>)을 기준으로 매칭됩니다.</p></div><h3 id="고정된-모델-표시-및-기능-사용자-정의" tabindex="-1">고정된 모델 표시 및 기능 사용자 정의 <a class="header-anchor" href="#고정된-모델-표시-및-기능-사용자-정의" aria-label="Permalink to &quot;고정된 모델 표시 및 기능 사용자 정의&quot;">​</a></h3><p>서드파티 제공자에서 모델을 고정하면 제공자별 ID가 <code>/model</code> 선택기에 그대로 나타나며 Claude Code가 모델이 지원하는 기능을 인식하지 못할 수 있습니다. 각 고정 모델에 대한 동반 환경 변수를 사용하여 표시 이름을 재정의하고 기능을 선언할 수 있습니다.</p><p>이러한 변수는 Bedrock, Vertex AI, Foundry와 같은 서드파티 제공자에서만 적용됩니다. Anthropic API를 직접 사용할 때는 효과가 없습니다.</p><table tabindex="0"><thead><tr><th>환경 변수</th><th>설명</th></tr></thead><tbody><tr><td><code>ANTHROPIC_DEFAULT_OPUS_MODEL_NAME</code></td><td><code>/model</code> 선택기에서 고정된 Opus 모델의 표시 이름. 설정하지 않으면 기본값은 모델 ID</td></tr><tr><td><code>ANTHROPIC_DEFAULT_OPUS_MODEL_DESCRIPTION</code></td><td><code>/model</code> 선택기에서 고정된 Opus 모델의 표시 설명. 설정하지 않으면 기본값은 <code>Custom Opus model</code></td></tr><tr><td><code>ANTHROPIC_DEFAULT_OPUS_MODEL_SUPPORTED_CAPABILITIES</code></td><td>고정된 Opus 모델이 지원하는 기능의 쉼표로 구분된 목록</td></tr></tbody></table><p>동일한 <code>_NAME</code>, <code>_DESCRIPTION</code>, <code>_SUPPORTED_CAPABILITIES</code> 접미사가 <code>ANTHROPIC_DEFAULT_SONNET_MODEL</code>, <code>ANTHROPIC_DEFAULT_HAIKU_MODEL</code>, <code>ANTHROPIC_CUSTOM_MODEL_OPTION</code>에도 사용 가능합니다.</p><p>Claude Code는 <a href="#adjust-effort-level">노력 수준</a> 및 <a href="/claude-code-docs-ko/common-workflows.html#use-extended-thinking-thinking-mode">확장 사고</a>와 같은 기능을 모델 ID와 알려진 패턴을 매칭하여 활성화합니다. Bedrock ARN이나 사용자 정의 배포 이름과 같은 제공자별 ID는 종종 이러한 패턴과 일치하지 않아 지원되는 기능이 비활성화됩니다. <code>_SUPPORTED_CAPABILITIES</code>를 설정하여 Claude Code에 모델이 실제로 지원하는 기능을 알리세요:</p><table tabindex="0"><thead><tr><th>기능 값</th><th>활성화 내용</th></tr></thead><tbody><tr><td><code>effort</code></td><td><a href="#adjust-effort-level">노력 수준</a> 및 <code>/effort</code> 명령</td></tr><tr><td><code>max_effort</code></td><td><code>max</code> 노력 수준</td></tr><tr><td><code>thinking</code></td><td><a href="/claude-code-docs-ko/common-workflows.html#use-extended-thinking-thinking-mode">확장 사고</a></td></tr><tr><td><code>adaptive_thinking</code></td><td>작업 복잡도에 따라 사고를 동적으로 할당하는 적응형 추론</td></tr><tr><td><code>interleaved_thinking</code></td><td>도구 호출 사이의 사고</td></tr></tbody></table><p><code>_SUPPORTED_CAPABILITIES</code>가 설정되면 나열된 기능이 활성화되고 나열되지 않은 기능은 매칭된 고정 모델에 대해 비활성화됩니다. 변수가 설정되지 않은 경우 Claude Code는 모델 ID를 기반으로 내장 감지로 폴백합니다.</p><p>이 예시는 Opus를 Bedrock 사용자 정의 모델 ARN에 고정하고, 친숙한 이름을 설정하며, 기능을 선언합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ANTHROPIC_DEFAULT_OPUS_MODEL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;arn:aws:bedrock:us-east-1:123456789012:custom-model/abc&#39;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ANTHROPIC_DEFAULT_OPUS_MODEL_NAME</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;Opus via Bedrock&#39;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ANTHROPIC_DEFAULT_OPUS_MODEL_DESCRIPTION</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;Opus 4.6 routed through a Bedrock custom endpoint&#39;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ANTHROPIC_DEFAULT_OPUS_MODEL_SUPPORTED_CAPABILITIES</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;effort,max_effort,thinking,adaptive_thinking,interleaved_thinking&#39;</span></span></code></pre></div><h3 id="버전별-모델-id-재정의" tabindex="-1">버전별 모델 ID 재정의 <a class="header-anchor" href="#버전별-모델-id-재정의" aria-label="Permalink to &quot;버전별 모델 ID 재정의&quot;">​</a></h3><p>위의 패밀리 수준 환경 변수는 패밀리 별칭당 하나의 모델 ID를 구성합니다. 동일한 패밀리 내의 여러 버전을 서로 다른 제공자 ID에 매핑해야 하는 경우 <code>modelOverrides</code> 설정을 대신 사용하세요.</p><p><code>modelOverrides</code>는 개별 Anthropic 모델 ID를 Claude Code가 제공자의 API에 보내는 제공자별 문자열에 매핑합니다. 사용자가 <code>/model</code> 선택기에서 매핑된 모델을 선택하면 Claude Code는 기본 제공 기본값 대신 구성된 값을 사용합니다.</p><p>이를 통해 엔터프라이즈 관리자는 거버넌스, 비용 할당 또는 지역 라우팅을 위해 각 모델 버전을 특정 Bedrock 추론 프로파일 ARN, Vertex AI 버전 이름 또는 Foundry 배포 이름으로 라우팅할 수 있습니다.</p><p><a href="/claude-code-docs-ko/settings.html#settings-files">설정 파일</a>에서 <code>modelOverrides</code>를 설정하세요:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;modelOverrides&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;claude-opus-4-6&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;arn:aws:bedrock:us-east-2:123456789012:application-inference-profile/opus-prod&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;claude-opus-4-5-20251101&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;arn:aws:bedrock:us-east-2:123456789012:application-inference-profile/opus-45-prod&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;claude-sonnet-4-6&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;arn:aws:bedrock:us-east-2:123456789012:application-inference-profile/sonnet-prod&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>키는 <a href="https://platform.claude.com/docs/en/about-claude/models/overview" target="_blank" rel="noreferrer">모델 개요</a>에 나열된 대로 Anthropic 모델 ID여야 합니다. 날짜가 포함된 모델 ID의 경우 거기에 표시된 대로 날짜 접미사를 정확히 포함하세요. 알 수 없는 키는 무시됩니다.</p><p>재정의는 <code>/model</code> 선택기의 각 항목을 지원하는 기본 제공 모델 ID를 교체합니다. Bedrock에서 재정의는 Claude Code가 시작 시 자동으로 검색하는 추론 프로파일보다 우선합니다. <code>ANTHROPIC_MODEL</code>, <code>--model</code>, 또는 <code>ANTHROPIC_DEFAULT_*_MODEL</code> 환경 변수를 통해 직접 제공한 값은 그대로 제공자에게 전달되며 <code>modelOverrides</code>에 의해 변환되지 않습니다.</p><p><code>modelOverrides</code>는 <code>availableModels</code>와 함께 작동합니다. 허용 목록은 재정의 값이 아닌 Anthropic 모델 ID를 기준으로 평가되므로 Opus 버전이 ARN에 매핑된 경우에도 <code>availableModels</code>의 <code>&quot;opus&quot;</code> 항목은 계속 매칭됩니다.</p><h3 id="프롬프트-캐싱-구성" tabindex="-1">프롬프트 캐싱 구성 <a class="header-anchor" href="#프롬프트-캐싱-구성" aria-label="Permalink to &quot;프롬프트 캐싱 구성&quot;">​</a></h3><p>Claude Code는 성능 최적화 및 비용 절감을 위해 자동으로 <a href="https://platform.claude.com/docs/en/build-with-claude/prompt-caching" target="_blank" rel="noreferrer">프롬프트 캐싱</a>을 사용합니다. 전역적으로 또는 특정 모델 등급에 대해 프롬프트 캐싱을 비활성화할 수 있습니다:</p><table tabindex="0"><thead><tr><th>환경 변수</th><th>설명</th></tr></thead><tbody><tr><td><code>DISABLE_PROMPT_CACHING</code></td><td><code>1</code>로 설정하면 모든 모델에 대해 프롬프트 캐싱 비활성화(모델별 설정보다 우선)</td></tr><tr><td><code>DISABLE_PROMPT_CACHING_HAIKU</code></td><td><code>1</code>로 설정하면 Haiku 모델에 대해서만 프롬프트 캐싱 비활성화</td></tr><tr><td><code>DISABLE_PROMPT_CACHING_SONNET</code></td><td><code>1</code>로 설정하면 Sonnet 모델에 대해서만 프롬프트 캐싱 비활성화</td></tr><tr><td><code>DISABLE_PROMPT_CACHING_OPUS</code></td><td><code>1</code>로 설정하면 Opus 모델에 대해서만 프롬프트 캐싱 비활성화</td></tr></tbody></table><p>이러한 환경 변수는 프롬프트 캐싱 동작에 대한 세밀한 제어를 제공합니다. 전역 <code>DISABLE_PROMPT_CACHING</code> 설정은 모델별 설정보다 우선하므로 필요할 때 모든 캐싱을 빠르게 비활성화할 수 있습니다. 모델별 설정은 특정 모델을 디버깅하거나 캐싱 구현이 다를 수 있는 클라우드 제공자와 작업할 때와 같이 선택적 제어에 유용합니다.</p>`,109)])])}const u=t(d,[["render",i]]);export{k as __pageData,u as default};
